class ParkingLot {
    private:
        int n;
        set<int> used;
        // (-distance / 2, start_pos)
        set<pair<int, int>> dist;

    void use(int p) {
        if (used.count(p)) {
            return;
        }
        auto t = used.lower_bound(p); // >= p, indeed > p
        int a = 0, b = n + 1;
        if (t != used.end()) {
            b = *t;
        }
        if (t != used.begin()) {
            a = *(--t);
        }
        if (a > 0 && b <= n) {
            dist.erase({-(b - a) / 2, a});
        }
        if (a > 0) {
            dist.insert({-(p - a) / 2, a});
        }
        if (b <= n) {
            dist.insert({-(b - p) / 2, p});
        }
        used.insert(p);
    }

    void unuse(int p) {
        auto t = used.find(p);
        if (t == used.end()) {
            return;
        }
        int a = 0, b = n + 1;
        auto t1 = t;
        if (++t1 != used.end()) {;
            b = *t1;
        }
        if (t != used.begin()) {
            a = *(--t);
        }
        if (a > 0) {
            dist.erase({-(p - a) / 2, a});
        }
        if (b <= n) {
            dist.erase({-(b - p) / 2, p});
        }
        if (a > 0 && b <= n) {
            dist.insert({-(b - a) / 2, a});
        }
        used.erase(p);
    }

    public:
       ParkingLot(int n): n(n) {}
       int insert_car() {
           if (used.size() >= n) {
               // No space.
               return 0;
           }
           if (used.empty()) {
               used.insert(1);
               return 1;
           }
           int p = 0, d = 0;
           if (*used.begin() > 1) {
               p = 1;
               d = *used.begin() - 1;
           }
           if (!dist.empty() && dist.begin()->first < 0 && -dist.begin()->first > d) {
               d = -dist.begin()->first;
               p = dist.begin()->second + d;      
           }
           if (*used.rbegin() < n && n - (*used.rbegin()) > d) {
               p = n;
               d = n - (*used.rbegin());
           }
           if (p) {
               use(p);
           }
           return p;
       }

       void remove_car(int pos) {
           unuse(pos);
       }
};

int main() {
    ParkingLot lot(5);
    cout << lot.insert_car() << endl;
